"use client";

import { useRef } from "react";
import Image from "next/image";
import Link from "next/link";
import { motion, useScroll, useTransform } from "framer-motion";

interface HeroProps {
  name: string;
  tagline: string;
}

const fade = (delay: number) => ({
  initial: { opacity: 0, y: 30 },
  animate: {
    opacity: 1,
    y: 0,
    transition: {
      duration: 1,
      delay,
      ease: [0.25, 0.1, 0.25, 1] as [number, number, number, number],
    },
  },
});

export default function Hero({ name, tagline }: HeroProps) {
  const ref = useRef<HTMLDivElement>(null);
  const { scrollYProgress } = useScroll({
    target: ref,
    offset: ["start start", "end start"],
  });

  // Slower parallax for image, faster fade for content
  const imageY = useTransform(scrollYProgress, [0, 1], ["0%", "50%"]);
  const contentOpacity = useTransform(scrollYProgress, [0, 0.8], [1, 0]);
  const contentY = useTransform(scrollYProgress, [0, 1], ["0%", "30%"]);

  return (
    <div ref={ref} className="relative h-[100dvh] overflow-hidden w-full flex items-center justify-center">
      {/* Background image with parallax */}
      <motion.div
        className="absolute inset-0 z-0 origin-top"
        style={{ y: imageY }}
      >
        <Image
          src="/images/stock/italian-pizza-2025-03-15-11-44-58-utc-scaled.jpg"
          alt="Restaurant Atmosphere"
          fill
          priority
          className="object-cover scale-105"
          sizes="100vw"
          quality={85}
        />
        {/* Gradient overlay */}
        <div className="absolute inset-0 bg-gradient-to-b from-brand-dark/80 via-brand-dark/50 to-brand-dark" />
      </motion.div>

      {/* Content */}
      <motion.div
        style={{ opacity: contentOpacity, y: contentY }}
        className="relative z-10 flex h-full w-full flex-col items-center justify-center px-6 text-center mt-12"
      >
        {/* Decorative line */}
        <motion.div
          {...fade(0.1)}
          className="mb-8 h-px w-16 bg-brand-orange"
        />

        <motion.h1
          {...fade(0.3)}
          className="font-heading text-5xl font-bold uppercase tracking-[0.15em] text-brand-cream md:text-7xl lg:text-8xl drop-shadow-lg"
        >
          {name}
        </motion.h1>

        <motion.p
          {...fade(0.5)}
          className="mt-6 max-w-xl text-lg leading-relaxed text-brand-cream/80 md:text-xl font-light tracking-wide"
        >
          {tagline}
        </motion.p>

        <motion.div
          {...fade(0.62)}
          className="mt-6 flex flex-wrap items-center justify-center gap-3 text-xs uppercase tracking-[0.18em] text-brand-cream/70"
        >
          <span className="rounded-full border border-brand-cream/15 bg-brand-dark/25 px-4 py-2 backdrop-blur-sm">
            Villeneuve
          </span>
          <span className="rounded-full border border-brand-cream/15 bg-brand-dark/25 px-4 py-2 backdrop-blur-sm">
            Cuisine maison
          </span>
          <span className="rounded-full border border-brand-cream/15 bg-brand-dark/25 px-4 py-2 backdrop-blur-sm">
            Réservation en 1 minute
          </span>
        </motion.div>

        {/* CTAs */}
        <motion.div
          {...fade(0.7)}
          className="mt-12 flex flex-col gap-4 sm:flex-row shadow-xl"
        >
          <motion.div whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}>
            <Link
              href="/reservation"
              className="group relative flex items-center justify-center overflow-hidden rounded-sm bg-brand-orange px-8 py-4 font-heading text-sm uppercase tracking-[0.2em] text-brand-dark transition-all hover:bg-brand-cream shadow-[0_0_15px_rgba(251,143,44,0.3)] hover:shadow-[0_0_25px_rgba(251,143,44,0.6)]"
            >
              <span className="relative z-10">Réserver votre table</span>
            </Link>
          </motion.div>
          <motion.div whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}>
            <Link
              href="/carte-des-mets"
              className="flex items-center justify-center rounded-sm border border-brand-cream/30 px-8 py-4 font-heading text-sm uppercase tracking-[0.2em] text-brand-cream transition-all hover:border-brand-cream hover:bg-brand-cream/10 backdrop-blur-sm"
            >
              Découvrir nos créations
            </Link>
          </motion.div>
        </motion.div>
      </motion.div>

      {/* Scroll indicator */}
      <motion.div
        {...fade(1.2)}
        className="absolute bottom-10 z-20"
      >
        <motion.div
          animate={{ y: [0, 8, 0] }}
          transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
        >
          <svg
            width="20"
            height="30"
            viewBox="0 0 20 30"
            fill="none"
            className="text-brand-cream/40"
          >
            <rect
              x="1"
              y="1"
              width="18"
              height="28"
              rx="9"
              stroke="currentColor"
              strokeWidth="1.5"
            />
            <circle cx="10" cy="10" r="2" fill="currentColor" />
          </svg>
        </motion.div>
      </motion.div>

      {/* Seamless blend to next section */}
      <div className="absolute bottom-0 left-0 right-0 h-32 bg-gradient-to-t from-brand-dark to-transparent z-10 pointer-events-none" />
    </div>
  );
}
