"use client";

import Image from "next/image";
import Link from "next/link";
import { motion } from "framer-motion";
import ScrollReveal from "./ScrollReveal";
import { urlFor } from "@/sanity/lib/client";

interface Dish {
  name: string;
  slug?: { current: string } | string;
  description: string;
  price: number;
  image?: { asset?: { _ref: string } } | string;
}

interface SignatureDishesProps {
  dishes: Dish[];
}

function getImageSrc(dish: Dish): string {
  if (typeof dish.image === "string") return dish.image;
  if (dish.image?.asset?._ref) return urlFor(dish.image).width(600).height(700).url();
  return "/images/food/romaine.png";
}

function getSlug(dish: Dish): string {
  if (typeof dish.slug === "string") return dish.slug;
  return dish.slug?.current ?? "";
}

export default function SignatureDishes({ dishes }: SignatureDishesProps) {
  return (
    <section className="bg-brand-navy py-24 md:py-32">
      <div className="mx-auto max-w-7xl px-6 lg:px-10">
        <ScrollReveal className="text-center">
          <span className="font-heading text-xs uppercase tracking-[0.3em] text-brand-orange">
            La carte
          </span>
          <h2 className="mt-4 font-heading text-3xl font-bold uppercase tracking-wide text-brand-cream md:text-4xl lg:text-5xl">
            Nos signatures
          </h2>
          <div className="mx-auto mt-4 h-px w-12 bg-brand-orange" />
        </ScrollReveal>

        <div className="mt-16 grid gap-8 md:grid-cols-3">
          {dishes.map((dish, i) => (
            <ScrollReveal key={getSlug(dish) || i} delay={i * 0.15} direction="up">
              <Link
                href="/carte-des-mets"
                className="group block h-full"
                aria-label={`Découvrir ${dish.name} dans la carte`}
              >
                <motion.div
                  whileHover={{ y: -10 }}
                  transition={{ duration: 0.4, ease: [0.22, 1, 0.36, 1] }}
                  className="relative h-full min-h-[400px] overflow-hidden rounded-sm shadow-xl"
                >
                  <Image
                    src={getImageSrc(dish)}
                    alt={dish.name}
                    fill
                    className="object-cover transition-transform duration-[1.5s] group-hover:scale-110 ease-out"
                    sizes="(max-width: 768px) 100vw, 33vw"
                  />
                  {/* Hover overlay with noise */}
                  <div className="absolute inset-0 bg-gradient-to-t from-brand-dark via-brand-dark/40 to-transparent opacity-70 transition-opacity duration-500 group-hover:opacity-90" />
                  <div className="absolute inset-0 bg-noise mix-blend-overlay opacity-10" />

                  {/* Content */}
                  <div className="absolute inset-x-0 bottom-0 p-8 translate-y-4 transition-transform duration-500 group-hover:translate-y-0 ease-out">
                    <p className="font-heading text-2xl uppercase tracking-widest text-brand-cream drop-shadow-md">
                      {dish.name}
                    </p>
                    <p className="mt-3 text-sm text-brand-cream/70 line-clamp-2 opacity-0 transition-opacity duration-500 group-hover:opacity-100 font-light leading-relaxed">
                      {dish.description}
                    </p>
                    <div className="mt-4 flex items-center justify-between opacity-0 transition-opacity duration-500 delay-100 group-hover:opacity-100">
                      <p className="font-heading text-xl text-brand-orange font-bold">
                        {dish.price} <span className="text-sm font-normal">CHF</span>
                      </p>
                      <span className="text-brand-orange text-sm uppercase tracking-wider font-bold">
                        Voir la carte
                      </span>
                    </div>
                  </div>
                </motion.div>
              </Link>
            </ScrollReveal>
          ))}
        </div>

        <ScrollReveal className="mt-20 text-center" direction="up">
          <Link
            href="/carte-des-mets"
            className="group relative inline-flex items-center justify-center overflow-hidden rounded-sm border border-brand-orange/50 px-10 py-4 font-heading text-sm uppercase tracking-[0.2em] text-brand-cream transition-all hover:border-brand-orange"
          >
            <span className="absolute inset-0 bg-brand-orange/10 translate-y-full transition-transform duration-300 ease-out group-hover:translate-y-0" />
            <span className="relative z-10">Voir toute la carte</span>
          </Link>
        </ScrollReveal>
      </div>
    </section>
  );
}
